        e.id_emprestimo,
        l.titulo,
        e.data_saida,
        e.data_prevista,
        e.data_devolucao,
        CASE WHEN e.data_devolucao IS NULL THEN 'EM ABERTO' ELSE 'DEVOLVIDO' END AS situacao
    FROM Emprestimos e
    JOIN Livros l ON l.id_livro = e.id_livro_fk
    WHERE e.id_usuario_fk = p_id_usuario
    ORDER BY e.data_saida DESC;
END ;;
DELIMITER ;
